// ✅ Stateful — owns a controller, needs dispose
class SearchBar extends StatefulWidget {
  final ValueChanged<String> onChanged;
  const SearchBar({super.key, required this.onChanged});
  @override State<SearchBar> createState() => _SearchBarState();
}
class _SearchBarState extends State<SearchBar> {
  late final _ctrl = TextEditingController();

  @override
  void initState() {
    super.initState();
    _ctrl.addListener(() => widget.onChanged(_ctrl.text));
  }

  @override
  void dispose() {
    _ctrl.dispose(); // critical — controllers leak otherwise
    super.dispose();
  }

  @override Widget build(BuildContext context) =>
      TextField(controller: _ctrl);
}

// ❌ Anti-pattern — Stateful that just mirrors a parent prop
class Bad extends StatefulWidget {
  final int count;
  const Bad({super.key, required this.count});
  @override State<Bad> createState() => _BadState();
}
class _BadState extends State<Bad> {
  late int _local = widget.count; // diverges from parent — bug factory
  @override Widget build(_) => Text('$_local');
}

class FavoriteButton extends StatefulWidget {
  const FavoriteButton({super.key});
  @override State<FavoriteButton> createState() => _FavoriteButtonState();
}

class _FavoriteButtonState extends State<FavoriteButton> {
  // Small piece of state isolated in its own listenable
  final _liked = ValueNotifier<bool>(false);

  @override
  void dispose() {
    _liked.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Row(
      children: [
        const ExpensiveLabel(),                    // const, never rebuilds
        ValueListenableBuilder<bool>(
          valueListenable: _liked,
          builder: (_, liked, __) => IconButton(
            icon: Icon(liked ? Icons.favorite : Icons.favorite_border),
            onPressed: () => _liked.value = !_liked.value,
          ),
        ),
      ],
    );
  }
}

