class ProfilePage extends StatefulWidget {
  const ProfilePage({super.key});
  @override State<ProfilePage> createState() => _ProfilePageState();
}

class _ProfilePageState extends State<ProfilePage> {
  Profile? _profile;
  StreamSubscription? _sub;

  Future<void> _load() async {
    // Capture the messenger BEFORE the await — context might not be valid after
    final messenger = ScaffoldMessenger.of(context);
    try {
      final data = await api.fetchProfile();
      if (!mounted) return;                     // ✅ widget might be gone
      setState(() => _profile = data);
    } catch (e) {
      if (!mounted) return;
      messenger.showSnackBar(SnackBar(content: Text('$e')));
    }
  }

  @override
  void initState() {
    super.initState();
    // ✅ Subscription stored so we can cancel in dispose()
    _sub = api.profileChanges().listen((p) {
      if (!mounted) return;
      setState(() => _profile = p);
    });
    _load();
  }

  @override
  void dispose() {
    _sub?.cancel();   // ✅ never fires on a dead state
    super.dispose();
  }

  @override Widget build(_) => Text(_profile?.name ?? '...');
}

class _PostFeedState extends State<PostFeed> {
  late final AnimationController _shimmer;       // controller owns lifetime
  StreamSubscription? _sub;

  @override
  void initState() {
    super.initState();
    // ✅ Allocate things that don't need context
    _shimmer = AnimationController(
      vsync: this, duration: const Duration(milliseconds: 800),
    )..repeat();
  }

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    // ✅ Resubscribe when Provider/Stream from inherited tree changes
    _sub?.cancel();
    final feed = context.read<FeedRepository>();
    _sub = feed.watch().listen((posts) {
      if (mounted) setState(() => _posts = posts);
    });
  }

  @override
  void didUpdateWidget(covariant PostFeed old) {
    super.didUpdateWidget(old);
    if (old.userId != widget.userId) {
      _load(widget.userId);    // ✅ react to a constructor-arg change
    }
  }

  @override
  void dispose() {
    _shimmer.dispose();
    _sub?.cancel();
    super.dispose();
  }
}

// 1) The notifier holds the state
class CounterModel extends ChangeNotifier {
  int _value = 0;
  int get value => _value;
  void inc() { _value++; notifyListeners(); }
}

// 2) InheritedNotifier exposes it
class CounterScope extends InheritedNotifier<CounterModel> {
  const CounterScope({
    super.key,
    required CounterModel super.notifier,
    required super.child,
  });

  static CounterModel of(BuildContext context) {
    final scope = context
        .dependOnInheritedWidgetOfExactType<CounterScope>();
    assert(scope != null, 'CounterScope missing');
    return scope!.notifier!;
  }
}

// 3) Provide it
class App extends StatefulWidget {
  const App({super.key});
  @override State<App> createState() => _AppState();
}
class _AppState extends State<App> {
  final _model = CounterModel();
  @override void dispose() { _model.dispose(); super.dispose(); }
  @override Widget build(_) => CounterScope(
    notifier: _model,
    child: const Display(),
  );
}

// 4) Consume — rebuilds only this widget on notify
class Display extends StatelessWidget {
  const Display({super.key});
  @override Widget build(BuildContext context) {
    final model = CounterScope.of(context);
    return Text('${model.value}');
  }
}

